import React, { useState } from 'react';

const ANOS = [2026, 2025, 2024];
const MESES = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const initialData = () => {
  const data = {};
  ANOS.forEach(ano => {
    data[ano] = {};
    MESES.forEach(mes => {
      data[ano][mes] = {
        checked: false,
        file: null,
        fileUrl: '',
      };
    });
  });
  return data;
};

export default function AcompanhamentoSCM({ razaoSocial }) {
  console.log('AcompanhamentoSCM', { razaoSocial });
  const [dados, setDados] = useState(initialData());
  const [anosDesligados, setAnosDesligados] = useState({});
  const [anosOcultos, setAnosOcultos] = useState({});

  const handleCheck = (ano, mes) => {
    setDados(prev => ({
      ...prev,
      [ano]: {
        ...prev[ano],
        [mes]: {
          ...prev[ano][mes],
          checked: !prev[ano][mes].checked
        }
      }
    }));
  };

  const handleFileChange = (ano, mes, e) => {
    const file = e.target.files[0];
    if (file) {
      // Monta o nome: COMP_SCM_RAZAOSOCIAL_ANO_MES.pdf
      const nomeLimpo = (razaoSocial || "").normalize('NFD').replace(/[^\w\s]/gi, '').replace(/\s+/g, '_').toUpperCase();
      const nomeArquivo = `COMP_SCM_${nomeLimpo}_${ano}_${mes.toUpperCase()}.pdf`;
      const novoFile = new File([file], nomeArquivo, { type: file.type });
      const url = URL.createObjectURL(novoFile);
      setDados(prev => ({
        ...prev,
        [ano]: {
          ...prev[ano],
          [mes]: {
            ...prev[ano][mes],
            file: novoFile,
            fileUrl: url
          }
        }
      }));
      // Log da ação de upload
      fetch('http://localhost:5000/api/acao', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          acao: 'UPLOAD_PDF_SCM',
          usuario: razaoSocial || 'desconhecido',
          detalhes: { nomeArquivo, ano, mes }
        })
      });
    }
  };

  const handleDownload = (ano, mes) => {
    const { file, fileUrl } = dados[ano][mes];
    if (file && fileUrl) {
      const link = document.createElement('a');
      link.href = fileUrl;
      link.download = file.name;
      link.click();
      // Log da ação de download
      fetch('http://localhost:5000/api/acao', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          acao: 'DOWNLOAD_PDF_SCM',
          usuario: razaoSocial || 'desconhecido',
          detalhes: { nomeArquivo: file.name, ano, mes }
        })
      });
    }
  };

  if (!razaoSocial) {
    return <div style={{ padding: 24, color: 'red', fontWeight: 'bold', textAlign: 'center' }}>Cliente não selecionado ou parâmetro razaoSocial ausente na URL.</div>;
  }
  return (
    <div style={{ padding: 24, background: 'linear-gradient(120deg, #f4f8ff 60%, #e3eafc 100%)', minHeight: '100vh' }}>
      <h2 style={{ textAlign: 'center', marginBottom: 32, color: '#1976d2', letterSpacing: 1, fontWeight: 800, fontSize: 32, textShadow: '0 2px 8px #0001' }}>Acompanhamento SCM</h2>
      {ANOS.map(ano => {
        const todosMesesMarcados = MESES.every(mes => dados[ano][mes].checked);
        const desligado = anosDesligados[ano];
        const oculto = anosOcultos[ano];
        if (oculto) {
          return (
            <div key={ano} style={{ marginBottom: 12, display: 'flex', alignItems: 'center', gap: 12, background: '#f8f9fb', borderRadius: 8, padding: '10px 18px', boxShadow: '0 1px 4px #0001' }}>
              <span style={{ color: '#888', fontWeight: 700, fontSize: 20 }}>{ano} (oculto)</span>
              <button
                onClick={() => setAnosOcultos(prev => ({ ...prev, [ano]: false }))}
                style={{ background: '#fff', color: '#1976d2', border: '2px solid #1976d2', borderRadius: 6, padding: '4px 18px', fontWeight: 700, cursor: 'pointer', fontSize: 16, transition: 'all 0.2s' }}
                title="Exibir ano"
                onMouseOver={e => e.currentTarget.style.background='#e3eafc'}
                onMouseOut={e => e.currentTarget.style.background='#fff'}
              >Exibir ano</button>
            </div>
          );
        }
        return (
          <div key={ano} style={{
            marginBottom: 36,
            border: desligado ? '2.5px solid #d32f2f' : (todosMesesMarcados ? '2.5px solid #388e3c' : '2px solid #1976d2'),
            borderRadius: 16,
            background: desligado ? '#ffebee' : (todosMesesMarcados ? '#e8f5e9' : '#fafdff'),
            boxShadow: '0 4px 16px #0001',
            padding: 24,
            opacity: desligado ? 0.6 : 1,
            transition: 'all 0.2s',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', marginBottom: 18, gap: 12 }}>
              <input type="checkbox" checked={todosMesesMarcados} readOnly style={{ marginRight: 10, accentColor: '#388e3c', width: 22, height: 22, boxShadow: '0 1px 4px #0001' }} disabled={desligado} />
              <h3 style={{ color: desligado ? '#d32f2f' : (todosMesesMarcados ? '#388e3c' : '#1976d2'), margin: 0, fontWeight: 800, fontSize: 24, letterSpacing: 1 }}>{ano}</h3>
              {todosMesesMarcados && !desligado && (
                <span style={{ marginLeft: 10, color: '#388e3c', fontWeight: 700, fontSize: 26, textShadow: '0 1px 4px #0001' }}>✔</span>
              )}
              {desligado && (
                <span style={{ marginLeft: 10, color: '#d32f2f', fontWeight: 700, fontSize: 26, textShadow: '0 1px 4px #0001' }}>⏻</span>
              )}
              <button
                onClick={() => setAnosDesligados(prev => ({ ...prev, [ano]: !prev[ano] }))}
                style={{ marginLeft: 18, background: desligado ? '#d32f2f' : '#fff', color: desligado ? '#fff' : '#d32f2f', border: '2px solid #d32f2f', borderRadius: 6, padding: '4px 18px', fontWeight: 700, cursor: 'pointer', fontSize: 16, transition: 'all 0.2s' }}
                title={desligado ? 'Reativar ano' : 'Desligar ano'}
                onMouseOver={e => { if (!desligado) e.currentTarget.style.background='#ffeaea'; }}
                onMouseOut={e => { if (!desligado) e.currentTarget.style.background='#fff'; }}
              >
                {desligado ? 'Reativar ano' : 'Desligar ano'}
              </button>
              <button
                onClick={() => setAnosOcultos(prev => ({ ...prev, [ano]: true }))}
                style={{ marginLeft: 8, background: '#fff', color: '#888', border: '2px solid #888', borderRadius: 6, padding: '4px 18px', fontWeight: 700, cursor: 'pointer', fontSize: 16, transition: 'all 0.2s' }}
                title="Ocultar ano"
                onMouseOver={e => e.currentTarget.style.background='#f4f4f4'}
                onMouseOut={e => e.currentTarget.style.background='#fff'}
              >Ocultar ano</button>
            </div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 18 }}>
              {MESES.map(mes => (
                <div key={mes} style={{ minWidth: 220, maxWidth: 260, background: '#fff', borderRadius: 10, boxShadow: '0 2px 8px #0001', padding: 16, marginBottom: 8, display: 'flex', flexDirection: 'column', alignItems: 'flex-start', border: dados[ano][mes].checked ? '2px solid #388e3c' : '1.5px solid #dbeafe', opacity: desligado ? 0.5 : 1, transition: 'all 0.2s', position: 'relative' }}
                  onMouseOver={e => e.currentTarget.style.boxShadow='0 4px 16px #1976d233'}
                  onMouseOut={e => e.currentTarget.style.boxShadow='0 2px 8px #0001'}
                >
                  <label style={{ fontWeight: 700, marginBottom: 6, fontSize: 16, color: '#1976d2', letterSpacing: 0.5 }}>
                    <input type="checkbox" checked={dados[ano][mes].checked} onChange={() => handleCheck(ano, mes)} style={{ marginRight: 10 }} disabled={desligado} />
                    {mes}
                  </label>
                  <div style={{display:'flex', alignItems:'center', gap:10, marginBottom:10, width:'100%'}}>
                    <input type="file" accept="application/pdf" onChange={e => handleFileChange(ano, mes, e)} disabled={desligado} style={{ fontSize: 14, border: '1px solid #dbeafe', borderRadius: 4, padding: '2px 4px', background: '#fafdff' }} />
                    {dados[ano][mes].file && (
                      <span style={{fontSize:13, color:'#1976d2', fontWeight:600, wordBreak:'break-all'}}>{dados[ano][mes].file.name}</span>
                    )}
                  </div>
                  {dados[ano][mes].file && (
                    <button onClick={() => handleDownload(ano, mes)} style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 5, padding: '5px 16px', fontWeight: 700, cursor: 'pointer', fontSize: 15, boxShadow: '0 1px 4px #1976d233', transition: 'all 0.2s' }} disabled={desligado}
                      onMouseOver={e => e.currentTarget.style.background='#1251a3'}
                      onMouseOut={e => e.currentTarget.style.background='#1976d2'}
                    >
                      Download
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>
        );
      })}
    </div>
  );
}
